from math import exp, sin, cos, tan, asin

def Specular_OffNormal(THETA: Float64, mut RAT_1MR: Float64, mut RAT_TAU: Float64) -> Bool:
    var result: Bool = True
    var THETA1: Float64 = abs(THETA)
    if THETA1 > 3.14159265358979324 / 2.0 - 3.14159265358979324 / 180.0:
        RAT_TAU = 0.0
        RAT_1MR = 0.0
    elif THETA1 >= 3.14159265358979324 / 180.0:
        var N2: Float64 = 1.526
        var KL: Float64 = 55.0 * 0.006
        var TAU_A: Float64 = exp(-1.0 * KL)
        var RPERP: Float64 = ((N2 - 1.0) / (N2 + 1.0))**2
        var TAU0: Float64 = TAU_A * (1.0 - RPERP) * (1.0 - RPERP) / (1.0 - (RPERP * RPERP * TAU_A * TAU_A))
        var RHO0: Float64 = RPERP * (1.0 + (TAU_A * TAU0))
        var THETA2: Float64 = asin((sin(THETA1)) / N2)
        TAU_A = exp(-1.0 * KL / cos(THETA2))
        RPERP = (sin(THETA2 - THETA1) / sin(THETA2 + THETA1))**2
        var RPARL: Float64 = (tan(THETA2 - THETA1) / tan(THETA2 + THETA1))**2
        var TAUPERP: Float64 = TAU_A * (1.0 - RPERP) * (1.0 - RPERP) / (1.0 - (RPERP * RPERP * TAU_A * TAU_A))
        var TAUPARL: Float64 = TAU_A * (1.0 - RPARL) * (1.0 - RPARL) / (1.0 - (RPARL * RPARL * TAU_A * TAU_A))
        var RHOPERP: Float64 = RPERP * (1.0 + (TAU_A * TAUPERP))
        var RHOPARL: Float64 = RPARL * (1.0 + (TAU_A * TAUPARL))
        var TAU_ON: Float64 = (TAUPERP + TAUPARL) / 2.0
        var RHO_ON: Float64 = (RHOPERP + RHOPARL) / 2.0
        RAT_TAU = TAU_ON / TAU0
        RAT_1MR = (1.0 - RHO_ON) / (1.0 - RHO0)
    else:
        result = False
        RAT_TAU = 1.0
        RAT_1MR = 1.0
    return result
